class CloudElasticity:
    def __init__(self, min_instances=1, max_instances=10):
        self.min_instances = min_instances
        self.max_instances = max_instances
        self.current_instances = min_instances

    def check_load_and_scale(self, current_demand):
        # Scale up if demand exceeds 80% capacity per instance
        capacity_per_instance = 100
        needed_instances = (current_demand // capacity_per_instance) + 1

        if needed_instances > self.current_instances:
            if needed_instances <= self.max_instances:
                self.current_instances = needed_instances
                print(f"Scaling UP to {self.current_instances} instances")
            else:
                self.current_instances = self.max_instances
                print("At maximum capacity")

        # Scale down if demand falls below 30% capacity per instance
        elif needed_instances < self.current_instances * 0.3:
            if needed_instances >= self.min_instances:
                self.current_instances = needed_instances
                print(f"Scaling DOWN to {self.current_instances} instances")
            else:
                self.current_instances = self.min_instances
                print(f"Scaling DOWN to minimum {self.min_instances} instances")

        return self.current_instances

# Example usage
cloud = CloudElasticity()
print("Demand 150 units:", cloud.check_load_and_scale(150))
print("Demand 500 units:", cloud.check_load_and_scale(500))
print("Demand 20 units:", cloud.check_load_and_scale(20))

public class CloudBilling {
    private Map<String, Double> usageTracker = new HashMap<>();
    private Map<String, Double> ratePerUnit = new HashMap<>();

    public CloudBilling() {
        // Set pricing rates per service
        ratePerUnit.put("compute", 0.05);    // per hour
        ratePerUnit.put("storage", 0.02);    // per GB/month
        ratePerUnit.put("bandwidth", 0.10);  // per GB
    }

    public void recordUsage(String tenantId, String serviceType, double units) {
        String key = tenantId + "_" + serviceType;
        double currentUsage = usageTracker.getOrDefault(key, 0.0);
        usageTracker.put(key, currentUsage + units);
    }

    public double calculateBill(String tenantId) {
        double totalBill = 0.0;
        for (Map.Entry<String, Double> entry : usageTracker.entrySet()) {
            if (entry.getKey().startsWith(tenantId + "_")) {
                String serviceType = entry.getKey().split("_")[1];
                double usage = entry.getValue();
                totalBill += usage * ratePerUnit.get(serviceType);
            }
        }
        return totalBill;
    }

    public void generateInvoice(String tenantId) {
        double amount = calculateBill(tenantId);
        System.out.println("Invoice for " + tenantId + ": $" + amount);
        usageTracker.clear(); // Reset for next billing period
    }

    public static void main(String[] args) {
        CloudBilling billing = new CloudBilling();

        // Record usage for tenant-001
        billing.recordUsage("tenant-001", "compute", 100);   // 100 hours
        billing.recordUsage("tenant-001", "storage", 500);  // 500 GB

        System.out.println("Total bill: $" + billing.calculateBill("tenant-001"));
    }
}
